import React from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { Search, MapPin, User, LogOut, ShoppingBag } from 'lucide-react';

const Header = ({ isLoggedIn, cerrarSesion }) => {
  const navigate = useNavigate();

  return (
    <header style={headerContainer}>
      {/* Logo y Branding */}
      <div style={logoSection} onClick={() => navigate('/')}>
        <div style={logoIcon}>O</div>
        <span style={logoText}>OFERTAS<span style={{color: '#334155'}}>APP</span></span>
      </div>

      {/* Buscador Central */}
      <div style={searchBarContainer}>
        <Search size={18} style={searchIcon} />
        <input 
          type="text" 
          placeholder="Busca locales o productos..." 
          style={searchInput} 
        />
        <button style={searchBtn}>Buscar</button>
      </div>

      {/* Navegación Derecha */}
      <nav style={navLinks}>
        <Link to="/locales" style={iconLink}>
          <MapPin size={20} />
          <span style={iconLabel}>Cerca mío</span>
        </Link>

        {!isLoggedIn ? (
          <Link to="/login" style={loginBtn}>
            <User size={18} />
            <span>Ingresar</span>
          </Link>
        ) : (
          <div style={{ display: 'flex', gap: '15px', alignItems: 'center' }}>
            <Link to="/dashboard" style={iconLink}>
              <ShoppingBag size={20} />
              <span style={iconLabel}>Mi Panel</span>
            </Link>
            <button onClick={cerrarSesion} style={logoutBtn}>
              <LogOut size={18} />
            </button>
          </div>
        )}
      </nav>
    </header>
  );
};

/* --- ESTILOS --- */
const headerContainer = {
  display: 'flex',
  justifyContent: 'space-between',
  alignItems: 'center',
  padding: '10px 5%',
  background: '#ffffff',
  boxShadow: '0 4px 12px rgba(0,0,0,0.08)',
  position: 'sticky',
  top: 0,
  zIndex: 1000,
  height: '70px'
};

const logoSection = { display: 'flex', alignItems: 'center', gap: '10px', cursor: 'pointer' };
const logoIcon = { background: '#e67e22', color: 'white', padding: '5px 12px', borderRadius: '10px', fontWeight: 'bold', fontSize: '1.2rem' };
const logoText = { fontSize: '1.4rem', fontWeight: '800', color: '#e67e22', letterSpacing: '-0.5px' };

const searchBarContainer = {
  display: 'flex',
  alignItems: 'center',
  background: '#f1f5f9',
  padding: '5px 5px 5px 15px',
  borderRadius: '12px',
  width: '40%',
  gap: '10px'
};

const searchInput = { border: 'none', background: 'transparent', outline: 'none', width: '100%', fontSize: '0.95rem' };
const searchIcon = { color: '#94a3b8' };
const searchBtn = { background: '#e67e22', color: 'white', border: 'none', padding: '8px 20px', borderRadius: '8px', cursor: 'pointer', fontWeight: '600' };

const navLinks = { display: 'flex', alignItems: 'center', gap: '25px' };
const iconLink = { display: 'flex', flexDirection: 'column', alignItems: 'center', textDecoration: 'none', color: '#64748b', fontSize: '0.75rem' };
const iconLabel = { marginTop: '2px', fontWeight: '500' };

const loginBtn = { 
  display: 'flex', 
  alignItems: 'center', 
  gap: '8px', 
  background: '#1e293b', 
  color: 'white', 
  padding: '10px 20px', 
  borderRadius: '10px', 
  textDecoration: 'none', 
  fontWeight: '600',
  fontSize: '0.9rem'
};

const logoutBtn = { background: '#fee2e2', color: '#ef4444', border: 'none', padding: '10px', borderRadius: '10px', cursor: 'pointer' };

export default Header;
